import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';

class Square extends React.Component {
    render() {
        return (
            <div className="square">
                <h2>{name}</h2>
                <h2>{birthday} ({age})</h2>
            </div>
        );
    }
}

export default Square;

ReactDOM.render(
    <React.StrictMode>
        <Square />
    </React.StrictMode>,
    document.getElementById('root')
);
